88	Uart8250::clearIntr(int intrBit)
89	{
90	    if ((status & intrBit) == 0) {
91	        return;
92	    }
93	    status &= ~intrBit;
94	
95	    // Clear interrupt at the controller if neither TX nor RX is pending now
96	    if (!status) {
97	        platform->clearConsoleInt();
98	    }
99	}
